import React from "react";
import styles from "./product-details.module.css";
import GridLayout from "../layout/grid-layout";
import ProductPresentation from "./product-presentation";
import ProductInfo from "./product-info";
import { useParams } from "react-router-dom";
import productsData from "../homepage/product-listing/product.json";
import { useDispatch } from "react-redux";


interface ProductProps {
  id: number;
  name: string;
  price: number;
  img: string;
}

const ProductDetails: React.FC = () => {
  const { productId } = useParams();
  const dispatch = useDispatch();

  const thisProduct: ProductProps | undefined = productsData.find(
    (prod: ProductProps) => prod.id === Number(productId)
  );

  if (!thisProduct) {
    return <div>Product not found</div>;
  }

  // Create a 'product' object with the required structure
  const product = {
    id: thisProduct.id,
    img: thisProduct.img,
    name: thisProduct.name,
    price: thisProduct.price,
  };

  return (
    <div className={styles.product}>
      <div className="container">
        <GridLayout>
          <div className="left-side">
            <ProductPresentation imgSrc={thisProduct.img} />
          </div>
          <div className={styles.right_side}>
            {/* Pass the 'product' object to 'ProductInfo' */}
            <ProductInfo product={product} />
          </div>
        </GridLayout>
      </div>
    </div>
  );
};

export default ProductDetails;
